using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Preserve the old name so existing 500K documents remain readable and
        // direct SQL queries referencing c.Discriminator keep working.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed the default id format from "EntityType|Key" (e.g. "Product|123")
        // to just the raw key value. Preserve the legacy format for existing documents.
        modelBuilder.Entity<Product>().HasKey(p => p.Id);
        modelBuilder.Entity<Product>()
            .Property(p => p.Id)
            .ToJsonProperty("id")
            .HasValueGenerator<Microsoft.EntityFrameworkCore.Cosmos.ValueGeneration.IdValueGenerator>();

        // HasIndex is not supported by the Cosmos provider and now throws in EF Core 9.
        // Cosmos indexes are managed via the Azure indexing policy, not EF model config.

        modelBuilder.Entity<Product>().ToContainer("Products");
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

